<svg id="bg" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="100%" height="100%" preserveAspectRatio="xMidYMid meet" viewBox="192 20 2096 3648">
  <defs>
    <style>
      .cls-1 {
        fill: #f0f3f8;
      }
    </style>
    <image id="image" width="409" height="398" xlink:href="data:img/png;base64,"/>
    <image id="image-2" width="408" height="398" xlink:href="data:img/png;base64,"/>
  </defs>
  <image id="Background" width="2480" height="3508" xlink:href="data:img/png;base64,"/>
  <image id="WhatsApp_Image_2026-05-24_at_11.47.18_PM" data-name="WhatsApp Image 2026-05-24 at 11.47.18 PM" x="262" y="88" width="1957" height="3508" xlink:href="data:img/png;base64,"/>
  <rect class="cls-1" x="368" y="936" width="677" height="1509"/>
  <rect class="cls-1" x="916" y="1396" width="1089" height="1169"/>







<filter id="chair-green" x="-20%" y="-20%" width="140%" height="140%">
      <feFlood flood-color="#17b081" result="flood"/>
      <feComposite in="flood" in2="SourceAlpha" operator="in" result="mask"/>
      <feBlend in="mask" in2="SourceGraphic" mode="multiply"/>
      <feDropShadow dx="0" dy="4" stdDeviation="8" flood-color="#17b081" flood-opacity="0.6"/>
    </filter>
    @php
        $multiChairSplit = $avail['status'] === 'multi_chair' ? $avail['schedule'] : [];
        $assignedChair = $assignedChair ?? ($avail['status'] === 'single_chair' ? $avail['chair_id'] : null);
        $availableChairIds = $avail['available_chair_ids'] ?? [];

        $allChairs = \App\Models\Chair::pluck('name', 'id')->toArray();
        $chairData = [
            1 => ['x' => 365, 'y' => 1019, 'href' => '#image'],
            2 => ['x' => 365, 'y' => 1529, 'href' => '#image'],
            3 => ['x' => 365, 'y' => 2039, 'href' => '#image'],
            4 => ['x' => 1115, 'y' => 1529, 'href' => '#image-2'],
            5 => ['x' => 1115, 'y' => 1988, 'href' => '#image-2'],
            6 => ['x' => 1523, 'y' => 1529, 'href' => '#image'],
            7 => ['x' => 1523, 'y' => 1988, 'href' => '#image']
        ];
    @endphp

    @foreach($chairData as $cid => $data)
        @php
            $isMultiAssigned = in_array($cid, $multiChairSplit);
            $isAvailable = in_array($cid, $availableChairIds);
            $isSelected = ($avail['status'] === 'single_chair' && $isAvailable) || ($avail['status'] === 'multi_chair' && $isMultiAssigned);
            $chairName = $allChairs[$cid] ?? 'Chair ' . $cid;
        @endphp
        
        <use id="chair-{{ $cid }}" x="{{ $data['x'] }}" y="{{ $data['y'] }}" xlink:href="{{ $data['href'] }}" @if($isSelected) filter="url(#chair-green)" @endif/>
        <text x="{{ $data['x'] > 1500 ? $data['x'] + 430 : $data['x'] - 50 }}" y="{{ $data['y'] + 200 }}" font-size="60" font-family="Arial, sans-serif" fill="#333333" font-weight="bold" text-anchor="{{ $data['x'] > 1500 ? 'start' : 'end' }}" style="pointer-events:none;">{{ $loop->iteration }}</text>
    @endforeach

    @if($avail['status'] === 'single_chair')
        @php
            $initialChairId = $assignedChair;
            $initialData = $initialChairId ? ($chairData[$initialChairId] ?? null) : null;
            $initialName = $initialChairId ? ($allChairs[$initialChairId] ?? 'Chair ' . $initialChairId) : '';
            $initialStart = \Carbon\Carbon::parse(session('stylist_booking.start_time'))->format('g:i A');
            $initialEnd = \Carbon\Carbon::parse(session('stylist_booking.end_time'))->format('g:i A');
        @endphp
        <g id="chair-details-box" @if(!$initialData) style="display:none" @endif>
            <rect id="chair-details-rect" x="{{ $initialData ? $initialData['x'] - 20 : 0 }}" y="{{ $initialData ? $initialData['y'] - 120 : 0 }}" width="560" height="100" fill="#fff" rx="16" filter="drop-shadow(0px 8px 20px rgba(0,0,0,0.15))"/>
            <text id="chair-details-line1" x="{{ $initialData ? $initialData['x'] + 10 : 0 }}" y="{{ $initialData ? $initialData['y'] - 75 : 0 }}" font-size="32" fill="#111" font-weight="bold">{{ $initialName }}: {{ $initialStart }} - {{ $initialEnd }}</text>
            <text id="chair-details-line2" x="{{ $initialData ? $initialData['x'] + 10 : 0 }}" y="{{ $initialData ? $initialData['y'] - 40 : 0 }}" font-size="28" fill="#666">(Full Duration)</text>
        </g>
    @else
        @foreach($chairData as $cid => $data)
            @php
                $isMultiAssigned = in_array($cid, $multiChairSplit);
                $isSelected = $avail['status'] === 'multi_chair' && $isMultiAssigned;
                $chairName = $allChairs[$cid] ?? 'Chair ' . $cid;
            @endphp

            @if($isSelected)
                @php
                    $hourIndex = array_search($cid, $multiChairSplit);
                    $startHour = \Carbon\Carbon::parse(session('stylist_booking.start_time'))->addHours($hourIndex)->format('g:i A');
                    $endHour = \Carbon\Carbon::parse(session('stylist_booking.start_time'))->addHours($hourIndex + 1)->format('g:i A');
                    $hourLabel = ($hourIndex == 0) ? '1st Hour' : (($hourIndex == 1) ? '2nd Hour' : 'Hour '.($hourIndex+1));
                @endphp
                <rect x="{{ $data['x'] - 20 }}" y="{{ $data['y'] - 120 }}" width="560" height="100" fill="#fff" rx="16" filter="drop-shadow(0px 8px 20px rgba(0,0,0,0.15))"/>
                <text x="{{ $data['x'] + 10 }}" y="{{ $data['y'] - 75 }}" font-size="32" fill="#111" font-weight="bold">{{ $chairName }}: {{ $startHour }} - {{ $endHour }}</text>
                <text x="{{ $data['x'] + 10 }}" y="{{ $data['y'] - 40 }}" font-size="28" fill="#666">({{ $hourLabel }})</text>
            @endif
        @endforeach
    @endif
    @if($avail['status'] === 'multi_chair' && count($multiChairSplit) > 1)
        <!-- Arrow Defs -->
        <defs>
            <marker id="arrowhead" markerWidth="15" markerHeight="10.5" refX="13.5" refY="5.25" orient="auto">
                <polygon points="0 0, 15 5.25, 0 10.5" fill="#17b081" />
            </marker>
        </defs>
        
        @for($i = 0; $i < count($multiChairSplit) - 1; $i++)
            @php
                $fromCid = $multiChairSplit[$i];
                $toCid = $multiChairSplit[$i+1];
                if (isset($chairData[$fromCid]) && isset($chairData[$toCid])) {
                    $fromData = $chairData[$fromCid];
                    $toData = $chairData[$toCid];
                    
                    // Chair center is roughly x + 204, y + 199
                    $fromX = $fromData['x'] + 204;
                    $fromY = $fromData['y'] + 199;
                    $toX = $toData['x'] + 204;
                    $toY = $toData['y'] + 199;
                }
            @endphp
            @if(isset($fromX))
                <!-- A nice thick dashed arrow -->
                <line x1="{{ $fromX }}" y1="{{ $fromY }}" x2="{{ $toX }}" y2="{{ $toY }}" stroke="#17b081" stroke-width="12" stroke-dasharray="24,14" marker-end="url(#arrowhead)" style="filter: drop-shadow(0px 4px 8px rgba(0,0,0,0.3));" />
            @endif
        @endfor
    @endif
</svg>
